def longest_palindrome(s: str) -> str:
    if not s:
        return ""
    n = len(s)
    start, max_len = 0, 1

    def expand(left: int, right: int) -> tuple:
        while left >= 0 and right < n and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - 1  # valid palindrome bounds

    for i in range(n):
        # Odd length
        l, r = expand(i, i)
        if r - l + 1 > max_len:
            start, max_len = l, r - l + 1
        # Even length
        l, r = expand(i, i + 1)
        if r - l + 1 > max_len:
            start, max_len = l, r - l + 1

    return s[start:start + max_len]  Time complexity: O(n˛) — each of O(n) centers expands up to O(n) in worst case (e.g., all identical characters). Space: O(1) excluding output. (Manacher's algorithm achieves O(n) but is more complex.)
